1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Scenario {
14	  customer: { yearsWithMHPCO: number };
15	  steps: QuoteStep[];
16	}
17	
18	const BASE_PREMIUM: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	  moonstone: 25,
25	};
26	
27	const FIRST_INSURANCE_RATE = 0.1;
28	const PROCESSING_FEE = 5;
29	
30	const COMPONENT_TYPES = ["rune", "moonstone"];
31	const COMPONENT_BLOCK_SIZE = 3;
32	const COMPONENT_BLOCK_PREMIUM = 60;
33	
34	const isComponent = (type: string): boolean => COMPONENT_TYPES.includes(type);
35	
36	const typeBasePremium = (type: string, count: number): number =>
37	  isComponent(type) && count === COMPONENT_BLOCK_SIZE
38	    ? COMPONENT_BLOCK_PREMIUM
39	    : count * BASE_PREMIUM[type];
40	
41	const CURSE_RATE = 0.5;
42	const HIGH_ENCHANTMENT_THRESHOLD = 5;
43	const HIGH_ENCHANTMENT_RATE = 0.3;
44	
45	const surchargeForItem = (item: Item): number => {
46	  const base = BASE_PREMIUM[item.type];
47	  const curse = item.cursed ? CURSE_RATE * base : 0;
48	  const highEnchantment =
49	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
50	      ? HIGH_ENCHANTMENT_RATE * base
51	      : 0;
52	  return curse + highEnchantment;
53	};
54	
55	const itemSurcharges = (items: Item[]): number =>
56	  items.reduce((sum, item) => sum + surchargeForItem(item), 0);
57	
58	const countByType = (items: Item[]): Map<string, number> => {
59	  const counts = new Map<string, number>();
60	  for (const item of items) {
61	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
62	  }
63	  return counts;
64	};
65	
66	const policyBasePremium = (items: Item[]): number =>
67	  [...countByType(items)].reduce(
68	    (total, [type, count]) => total + typeBasePremium(type, count),
69	    0,
70	  );
71	
72	const quotePremium = (step: QuoteStep): number => {
73	  const policyBase = policyBasePremium(step.items);
74	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
75	  return Math.ceil(
76	    policyBase + itemSurcharges(step.items) + firstInsurance + PROCESSING_FEE,
77	  );
78	};
79	
80	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
81	  return {
82	    results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
83	  };
84	};
